<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***DataConsistencyValidator*Validatesandmaintainsdataconsistencyacrossallmodules*/require_once__DIR__.'/E2EClient.php';require_once__DIR__.'/APIResponse.php';classDataConsistencyValidator{private$pdo;private$issues=[];publicfunction__construct(){global$pdo;$this->pdo=$pdo;}/***Validatealldataconsistency*/publicfunctionvalidateAll(){$this->issues=[];$this->validatePersonilReferences();$this->validateUnsurBagianRelationships();$this->validateJabatanConsistency();$this->validateDuplicateRecords();$this->validateDataIntegrity();return['success'=>empty($this->issues),'issues'=>$this->issues,'summary'=>$this->generateSummary(),'timestamp'=>date('c')];}/***Validatepersonilforeignkeyreferences*/privatefunctionvalidatePersonilReferences(){/Checkunsurreferences$sql="SELECTp.id,p.nama,p.id_unsur,u.nama_unsurFROMpersonilpLEFTJOINunsuruONp.id_unsur=u.idWHEREp.id_unsur>0ANDu.idISnullANDp.is_deleted=0";$stmt=$this->pdo->query($sql);$orphans=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($orphansas$orphan){$this->issues[]=['type'=>'orphaned_unsur_reference','severity'=>'high','table'=>'personil','record_id'=>$orphan['id'],'description'=>"Personil'{$orphan['nama']}'referencesnon-existentunsurID:{$orphan['id_unsur']}",'suggestion'=>'Updatepersonilunsur_idtovalidvalueorremovereference'];}/Checkbagianreferences$sql="SELECTp.id,p.nama,p.id_bagian,b.nama_bagianFROMpersonilpLEFTJOINbagianbONp.id_bagian=b.idWHEREp.id_bagian>0ANDb.idISnullANDp.is_deleted=0";$stmt=$this->pdo->query($sql);$orphans=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($orphansas$orphan){$this->issues[]=['type'=>'orphaned_bagian_reference','severity'=>'high','table'=>'personil','record_id'=>$orphan['id'],'description'=>"Personil'{$orphan['nama']}'referencesnon-existentbagianID:{$orphan['id_bagian']}",'suggestion'=>'Updatepersonilbagian_idtovalidvalueorremovereference'];}/Checkjabatanreferences$sql="SELECTp.id,p.nama,p.id_jabatan,j.nama_jabatanFROMpersonilpLEFTJOINjabatanjONp.id_jabatan=j.idWHEREp.id_jabatan>0ANDj.idISnullANDp.is_deleted=0";$stmt=$this->pdo->query($sql);$orphans=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($orphansas$orphan){$this->issues[]=['type'=>'orphaned_jabatan_reference','severity'=>'high','table'=>'personil','record_id'=>$orphan['id'],'description'=>"Personil'{$orphan['nama']}'referencesnon-existentjabatanID:{$orphan['id_jabatan']}",'suggestion'=>'Updatepersoniljabatan_idtovalidvalueorremovereference'];}}/***Validateunsur-bagianrelationships*/privatefunctionvalidateUnsurBagianRelationships(){/Checkbagianwithinvalidunsurreferences$sql="SELECTb.id,b.nama_bagian,b.id_unsur,u.nama_unsurFROMbagianbLEFTJOINunsuruONb.id_unsur=u.idWHEREb.id_unsur>0ANDu.idISnull";$stmt=$this->pdo->query($sql);$orphans=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($orphansas$orphan){$this->issues[]=['type'=>'orphaned_unsur_in_bagian','severity'=>'high','table'=>'bagian','record_id'=>$orphan['id'],'description'=>"Bagian'{$orphan['nama_bagian']}'referencesnon-existentunsurID:{$orphan['id_unsur']}",'suggestion'=>'Updatebagianunsur_idtovalidvalue'];}/Checkforduplicateurutanwithinsameunsur$sql="SELECTb1.id,b1.nama_bagian,b1.id_unsur,b1.urutan,u.nama_unsurFROMbagianb1JOINunsuruONb1.id_unsur=u.idJOINbagianb2ONb1.id_unsur=b2.id_unsurANDb1.urutan=b2.urutanANDb1.id!=b2.id";$stmt=$this->pdo->query($sql);$duplicates=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($duplicatesas$dup){$this->issues[]=['type'=>'duplicate_urutan_in_unsur','severity'=>'medium','table'=>'bagian','record_id'=>$dup['id'],'description'=>"Bagian'{$dup['nama_bagian']}'hasduplicateurutan{$dup['urutan']}inunsur'{$dup['nama_unsur']}'",'suggestion'=>'Updateurutantouniquevaluewithinunsur'];}}/***Validatejabatanconsistency*/privatefunctionvalidateJabatanConsistency(){/Checkjabatanwithinvalidunsurreferences$sql="SELECTj.id,j.nama_jabatan,j.id_unsur,u.nama_unsurFROMjabatanjLEFTJOINunsuruONj.id_unsur=u.idWHEREj.id_unsur>0ANDu.idISnull";$stmt=$this->pdo->query($sql);$orphans=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($orphansas$orphan){$this->issues[]=['type'=>'orphaned_unsur_in_jabatan','severity'=>'high','table'=>'jabatan','record_id'=>$orphan['id'],'description'=>"Jabatan'{$orphan['nama_jabatan']}'referencesnon-existentunsurID:{$orphan['id_unsur']}",'suggestion'=>'Updatejabatanunsur_idtovalidvalue'];}/Checkforduplicatejabatannameswithinsameunsur$sql="SELECTj1.id,j1.nama_jabatan,j1.id_unsur,u.nama_unsurFROMjabatanj1JOINunsuruONj1.id_unsur=u.idJOINjabatanj2ONj1.id_unsur=j2.id_unsurANDj1.nama_jabatan=j2.nama_jabatanANDj1.id!=j2.id";$stmt=$this->pdo->query($sql);$duplicates=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($duplicatesas$dup){$this->issues[]=['type'=>'duplicate_jabatan_in_unsur','severity'=>'medium','table'=>'jabatan','record_id'=>$dup['id'],'description'=>"Duplicatejabatanname'{$dup['nama_jabatan']}'inunsur'{$dup['nama_unsur']}'",'suggestion'=>'Renamejabatantouniquevaluewithinunsur'];}}/***Validateduplicaterecords*/privatefunctionvalidateDuplicateRecords(){/CheckduplicateNRP$sql="SELECTp1.id,p1.nama,p1.nrpFROMpersonilp1JOINpersonilp2ONp1.nrp=p2.nrpANDp1.id!=p2.idWHEREp1.is_deleted=0ANDp2.is_deleted=0";$stmt=$this->pdo->query($sql);$duplicates=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($duplicatesas$dup){$this->issues[]=['type'=>'duplicate_nrp','severity'=>'high','table'=>'personil','record_id'=>$dup['id'],'description'=>"Personil'{$dup['nama']}'hasduplicateNRP:{$dup['nrp']}",'suggestion'=>'UpdateNRPtouniquevalue'];}/CheckduplicateNIP$sql="SELECTp1.id,p1.nama,p1.nipFROMpersonilp1JOINpersonilp2ONp1.nip=p2.nipANDp1.id!=p2.idWHEREp1.nipISNOTnullANDp1.nip!=''ANDp1.is_deleted=0ANDp2.is_deleted=0";$stmt=$this->pdo->query($sql);$duplicates=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($duplicatesas$dup){$this->issues[]=['type'=>'duplicate_nip','severity'=>'medium','table'=>'personil','record_id'=>$dup['id'],'description'=>"Personil'{$dup['nama']}'hasduplicateNIP:{$dup['nip']}",'suggestion'=>'UpdateNIPtouniquevalueorleaveempty'];}}/***Validatedataintegrity*/privatefunctionvalidateDataIntegrity(){/Checkpersonilwithmissingrequiredfields$sql="SELECTid,namaFROMpersonilWHERE(namaISnullORnama=''ORnrpISnullORnrp='')ANDis_deleted=0";$stmt=$this->pdo->query($sql);$invalid=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($invalidas$record){$this->issues[]=['type'=>'missing_required_fields','severity'=>'high','table'=>'personil','record_id'=>$record['id'],'description'=>"PersonilID{$record['id']}missingrequiredfields(namaornrp)",'suggestion'=>'Updatepersonilwithrequiredinformation'];}/Checkunsurwithmissingrequiredfields$sql="SELECTid,nama_unsurFROMunsurWHERE(nama_unsurISnullORnama_unsur=''ORkode_unsurISnullORkode_unsur='')";$stmt=$this->pdo->query($sql);$invalid=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($invalidas$record){$this->issues[]=['type'=>'missing_required_fields','severity'=>'high','table'=>'unsur','record_id'=>$record['id'],'description'=>"UnsurID{$record['id']}missingrequiredfields",'suggestion'=>'Updateunsurwithrequiredinformation'];}/Checkbagianwithmissingrequiredfields$sql="SELECTid,nama_bagianFROMbagianWHERE(nama_bagianISnullORnama_bagian=''ORid_unsurISnull)";$stmt=$this->pdo->query($sql);$invalid=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($invalidas$record){$this->issues[]=['type'=>'missing_required_fields','severity'=>'high','table'=>'bagian','record_id'=>$record['id'],'description'=>"BagianID{$record['id']}missingrequiredfields",'suggestion'=>'Updatebagianwithrequiredinformation'];}}/***Generatesummaryofvalidationresults*/privatefunctiongenerateSummary(){$summary=['total_issues'=>count($this->issues),'by_severity'=>['high'=>0,'medium'=>0,'low'=>0],'by_type'=>[],'by_table'=>[]];forforeach($this->issuesas$issue){$severity=$issue['severity']??'medium';$type=$issue['type']??'unknown';$table=$issue['table']??'unknown';$summary['by_severity'][$severity]++;$summary['by_type'][$type]=($summary['by_type'][$type]??0)+1;$summary['by_table'][$table]=($summary['by_table'][$table]??0)+1;}return$summary;}/***Auto-fixcommonissues*/publicfunctionautoFixIssues(){$fixed=[];$failed=[];forforeach($this->issuesas$issue){try{switch($issue['type']){case'orphaned_unsur_reference':case'orphaned_bagian_reference':case'orphaned_jabatan_reference':/Setinvalidreferencesto0$field=$this->getFieldNameFromType($issue['type']);$sql="UPDATEpersonilSET{$field}=0WHEREid=?";$stmt=$this->pdo->prepare($sql);$stmt->execute([$issue['record_id']]);$fixed[]=$issue['record_id'];break;case'missing_required_fields':/Cannotauto-fixmissingrequireddata$failed[]=$issue['record_id'];break;default:$failed[]=$issue['record_id'];break;}}catch(Exception$e){$failed[]=$issue['record_id'];}}return['success'=>true,'fixed'=>$fixed,'failed'=>$failed,'timestamp'=>date('c')];}privatefunctiongetFieldNameFromType($type){$mapping=['orphaned_unsur_reference'=>'id_unsur','orphaned_bagian_reference'=>'id_bagian','orphaned_jabatan_reference'=>'id_jabatan'];return$mapping[$type]??'id';}}/APIendpointfordataconsistencyvalidationif(isset(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'action',FILTER_DEFAULT))&&filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'action',FILTER_DEFAULT)==='validate_consistency'){try{$validator=newDataConsistencyValidator();$result=$validator->validateAll();if(isset(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'auto_fix',FILTER_DEFAULT))&&filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'auto_fix',FILTER_DEFAULT)==='true'){$fixResult=$validator->autoFixIssues();$result['auto_fix']=$fixResult;}echojson_encode(APIResponse::success($result,'Dataconsistencyvalidationcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
